import * as React from "react";
import { useRef, useLayoutEffect } from "react";
import gsap from "gsap";
import { ScrollTrigger } from "gsap/ScrollTrigger";

gsap.registerPlugin(ScrollTrigger);

const TestScrollPage = () => {
  const sectionRef = useRef(null);
  const trackRef = useRef(null);

  useLayoutEffect(() => {
  if (typeof window === "undefined") return;

  const section = sectionRef.current;
  const track = trackRef.current;
  if (!section || !track) return;

  const tween = gsap.to(track, {
    xPercent: -200, // mover 3 paneles (300vw -> -200vw)
    ease: "none",
    scrollTrigger: {
      trigger: section,
      start: "top top",
      end: "+=1500",   // tramo largo para probar
      pin: true,
      scrub: 1,
      markers: true,
    },
  });

  return () => {
    tween.scrollTrigger && tween.scrollTrigger.kill();
    tween.kill();
  };
}, []);

  return (
    <main className="min-h-screen bg-slate-800 text-white">
      <h1 className="text-center py-10 text-3xl">TEST SCROLL HORIZONTAL</h1>

      <section
        ref={sectionRef}
        className="relative w-full h-screen overflow-hidden bg-slate-900"
      >
        <div
          ref={trackRef}
          className="flex w-[300vw] h-full"
        >
          <div className="w-screen h-full bg-red-500 flex items-center justify-center text-4xl">
            PANEL 1
          </div>
          <div className="w-screen h-full bg-green-500 flex items-center justify-center text-4xl">
            PANEL 2
          </div>
          <div className="w-screen h-full bg-blue-500 flex items-center justify-center text-4xl">
            PANEL 3
          </div>
        </div>
      </section>

      <section className="h-[150vh] bg-slate-700 flex items-center justify-center">
        <p>Contenido después del scroll horizontal</p>
      </section>
    </main>
  );
};

export default TestScrollPage;